import React from 'react';

const Awards = () => {
  return (
    <section className="awards">
      <div className="container">
        <div className="award-card reveal-scale">
          <div className="award-trophy">
            <i className="fa-solid fa-trophy"></i>
          </div>
          <div>
            <h3>Silver Award – Sabaragamuwa Province Entrepreneur Awards</h3>
            <p>
              Recognized for excellence and commitment to quality in the beauty and bridal industry. 
              This prestigious award honors Salon Udani's dedication to creating exceptional bridal experiences 
              and maintaining the highest standards of professional service.
            </p>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Awards;
